class Solution {
public:
    int reverse(int x) {
        if (x == INT_MIN) return 0;
        int reversed = 0;
        int sign = 1;
        if (x < 0) sign = -1;
        x = abs(x);
        while (x != 0) {
            int pop = x % 10;
            x = x / 10;
            if (reversed > INT_MAX / 10 || (reversed == INT_MAX / 10 && pop > 7)) {
                return 0;
            }
            reversed = reversed * 10 + pop;
        }
        return reversed * sign;
    }
};

